function qs(selector, root = document) { return root.querySelector(selector); }
function qsa(selector, root = document) { return Array.from(root.querySelectorAll(selector)); }
function clean(text) { return String(text || "").replace(/\s+/g, " ").trim(); }
function norm(text) { return clean(text).toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, ""); }
function randomItem(list) { return list[Math.floor(Math.random() * list.length)]; }
function saveState() { localStorage.setItem(STORAGE_KEY, JSON.stringify(state)); }
function loadState() { const base = { xp: 0, level: 1, hearts: 5, streak: 1, onboarded: false, profile: { name: "", goal: "viagem", level: "iniciante" }, completedLessons: [], reviewQueue: [], wrongAnswers: [] }; try { return { ...base, ...JSON.parse(localStorage.getItem(STORAGE_KEY) || "{}") }; } catch { return base; } }
let state = loadState();
let currentAudio = PHRASES[0];
let currentSpeaking = PHRASES[0];
let currentReview = null;
let currentExam = [];
let currentAlphabetIndex = 0;
function toast(message) { const el = qs('#toast'); if (!el) return; el.textContent = message; el.classList.add('show'); setTimeout(() => el.classList.remove('show'), 2200); }
function translit(text) { const map = { 'А':'a','а':'a','Б':'b','б':'b','В':'v','в':'v','Г':'g','г':'g','Д':'d','д':'d','Е':'ye','е':'ye','Ё':'yo','ё':'yo','Ж':'zh','ж':'zh','З':'z','з':'z','И':'i','и':'i','Й':'y','й':'y','К':'k','к':'k','Л':'l','л':'l','М':'m','м':'m','Н':'n','н':'n','О':'o','о':'o','П':'p','п':'p','Р':'r','р':'r','С':'s','с':'s','Т':'t','т':'t','У':'u','у':'u','Ф':'f','ф':'f','Х':'kh','х':'kh','Ц':'ts','ц':'ts','Ч':'ch','ч':'ch','Ш':'sh','ш':'sh','Щ':'shch','щ':'shch','Ы':'y','ы':'y','Э':'e','э':'e','Ю':'yu','ю':'yu','Я':'ya','я':'ya','Ь':'','ь':'','Ъ':'','ъ':'' }; return String(text || '').split('').map(c => map[c] ?? c).join(''); }
function allItems() { return [...VOCABULARY, ...PHRASES]; }
function findItem(query) { const q = norm(query); return allItems().find(item => norm(item.ru) === q || norm(item.pt) === q || norm(item.pron) === q) || allItems().find(item => norm(item.ru).includes(q) || norm(item.pt).includes(q) || norm(item.pron).includes(q)); }
function itemFrom(text) { const found = findItem(text); return found || { ru: clean(text), pt: 'conteúdo russo para estudar', pron: translit(text), cat: 'texto' }; }
function setImageFallbacks() { qsa('img').forEach(img => { img.addEventListener('error', () => { if (!img.dataset.fallbackDone) { img.dataset.fallbackDone = '1'; img.src = LOGO_BASE64; } }); }); }
function renderStats() { qs('#xpView').textContent = state.xp + ' XP'; qs('#levelView').textContent = 'Nível ' + state.level; qs('#heartView').textContent = '❤️'.repeat(state.hearts) + '♡'.repeat(Math.max(0, 5 - state.hearts)); qs('#streakView').textContent = state.streak + ' dia' + (state.streak === 1 ? '' : 's'); }
function addXP(value) { state.xp += value; state.level = Math.floor(state.xp / 120) + 1; saveState(); renderStats(); }
function loseHeart() { state.hearts = Math.max(0, state.hearts - 1); saveState(); renderStats(); }
function speak(text, rate = 0.9) { if (!('speechSynthesis' in window)) { toast('Som não disponível neste navegador'); return; } window.speechSynthesis.cancel(); const utter = new SpeechSynthesisUtterance(clean(text)); utter.lang = 'ru-RU'; utter.rate = rate; window.speechSynthesis.speak(utter); }
function listen(callback) { const SR = window.SpeechRecognition || window.webkitSpeechRecognition; if (!SR) { toast('Microfone não disponível neste navegador'); return; } const rec = new SR(); rec.lang = 'ru-RU'; rec.interimResults = false; rec.maxAlternatives = 1; rec.onstart = () => toast('Fale agora'); rec.onerror = () => toast('Não consegui ouvir'); rec.onresult = e => callback(e.results[0][0].transcript); rec.start(); }
function showSection(id) { qsa('.screen').forEach(section => section.classList.remove('active')); const target = qs('#' + id); if (target) target.classList.add('active'); qsa('nav button[data-screen]').forEach(button => button.classList.toggle('active', button.dataset.screen === id)); const titles = { home:['Painel','Comece sua rotina de russo.'], course:['Curso','Unidades do A1 ao C2.'], teacher:['Professor IA','Explicações úteis.'], alphabet:['Alfabeto','Letras com imagem e som.'], audio:['Áudio','Escuta guiada.'], writing:['Escrita','Cirílico e textos.'], speaking:['Fala','Microfone e prática.'], review:['Revisão','Ajuda para provas.'], exams:['Provas','Teste seu conhecimento.'], games:['Jogos','Aprenda brincando.'], dictionary:['Dicionário','Busca rápida.'], culture:['Cultura','História, contos e receitas.'], profile:['Perfil','Objetivo e progresso.'] }; const current = titles[id] || ['PUTIRUSU','Aprenda russo.']; qs('#pageTitle').textContent = current[0]; qs('#pageSubtitle').textContent = current[1]; qs('#sidebar').classList.remove('open'); }
function hideSplash() { const splash = qs('#splash'); if (!splash) return; splash.classList.add('hide'); setTimeout(() => { if (splash.parentNode) splash.parentNode.removeChild(splash); }, 700); }
function showWelcome() { qs('#welcome').classList.add('show'); qs('#welcome').classList.remove('hidden-screen'); }
function showOnboarding() { qs('#welcome').classList.remove('show'); qs('#welcome').classList.add('hidden-screen'); qs('#onboarding').classList.add('show'); qs('#onboarding').classList.remove('hidden-screen'); }
function enterApp() { qs('#welcome').classList.remove('show'); qs('#welcome').classList.add('hidden-screen'); qs('#onboarding').classList.remove('show'); qs('#onboarding').classList.add('hidden-screen'); qs('#app').classList.remove('app-hidden'); qs('#app').style.display = 'grid'; renderAll(); showSection('home'); }
function studyHTML(item) { return `<div class="study-card"><h2>${item.ru}</h2><div class="study-line"><strong>Tradução:</strong> ${item.pt}</div><div class="study-line"><strong>Pronúncia:</strong> ${item.pron || translit(item.ru)}</div><div class="study-line"><strong>Explicação:</strong> use para dizer "${item.pt}". Ouça, repita, escreva e responda.</div><div class="row"><button data-speak="${item.ru}">Ouvir</button><button data-slow="${item.ru}">Devagar</button><button data-review="${item.ru}">Salvar revisão</button></div><div class="exercise"><strong>Pergunta:</strong> Qual é a tradução?<input data-answer="${item.pt}" placeholder="Digite a tradução"><button data-check>Verificar</button><div class="feedback"></div></div></div>`; }
function wireStudy(root) { qsa('[data-speak]', root).forEach(button => button.onclick = () => speak(button.dataset.speak)); qsa('[data-slow]', root).forEach(button => button.onclick = () => speak(button.dataset.slow, 0.65)); qsa('[data-review]', root).forEach(button => button.onclick = () => { const item = itemFrom(button.dataset.review); if (!state.reviewQueue.find(entry => norm(entry.ru) === norm(item.ru))) state.reviewQueue.push(item); saveState(); toast('Salvo na revisão'); }); qsa('[data-check]', root).forEach(button => button.onclick = () => { const box = button.closest('.exercise'); const input = box.querySelector('input'); const feedback = box.querySelector('.feedback'); const ok = norm(input.value) === norm(input.dataset.answer); feedback.className = 'feedback ' + (ok ? 'good' : 'bad'); feedback.textContent = ok ? 'Certo!' : 'Resposta correta: ' + input.dataset.answer; if (ok) addXP(10); else { loseHeart(); state.wrongAnswers.push(input.dataset.answer); saveState(); } }); }
function renderCourse() { const levelsInCourse = [...new Set(COURSE_UNITS.map(unit => unit.level))]; qs('#levelTabs').innerHTML = levelsInCourse.map(level => `<button data-level="${level}">${level}</button>`).join(''); qsa('#levelTabs [data-level]').forEach(button => button.onclick = () => renderUnits(button.dataset.level)); renderUnits(levelsInCourse[0]); }
function renderUnits(level) { const units = COURSE_UNITS.filter(unit => unit.level === level); qs('#unitGrid').innerHTML = units.map(unit => { const index = COURSE_UNITS.indexOf(unit); return `<article class="unit-card"><p class="tag">${unit.level} · ${unit.theme}</p><h3>${unit.title}</h3><p>${unit.grammar}</p><p>${unit.items.length} conteúdos</p><button data-open="${index}">Abrir unidade</button></article>`; }).join(''); qsa('#unitGrid [data-open]').forEach(button => button.onclick = () => openLesson(Number(button.dataset.open))); }
function openLesson(index) { const unit = COURSE_UNITS[index]; const host = qs('#lessonView'); host.innerHTML = `<div class="unit-card"><p class="tag">${unit.level}</p><h2>${unit.title}</h2><div class="study-line"><strong>Explicação:</strong> ${unit.grammar}</div>${unit.items.map(item => studyHTML(itemFrom(item))).join('')}<button id="finishLesson">Concluir unidade</button></div>`; wireStudy(host); const finish = qs('#finishLesson'); if (finish) finish.onclick = () => { if (!state.completedLessons.includes(index)) state.completedLessons.push(index); addXP(50); saveState(); renderProfile(); toast('Unidade concluída'); }; }
function renderAlphabet() { qs('#alphabetGrid').innerHTML = ALPHABET.map((letter, index) => `<article class="panel alphabet-card" data-letter="${index}"><div class="emoji">${letter.emoji}</div><div class="letter">${letter.upper} ${letter.lower}</div><div class="sound">${letter.sound}</div><div>${letter.example} · ${letter.translation}</div></article>`).join(''); qsa('#alphabetGrid [data-letter]').forEach(card => card.onclick = () => showLetter(Number(card.dataset.letter))); showLetter(currentAlphabetIndex); }
function showLetter(index) { currentAlphabetIndex = index; const letter = ALPHABET[index]; const host = qs('#letterDetail'); host.innerHTML = `<div class="study-card"><h2>${letter.upper} ${letter.lower}</h2><div class="study-line"><strong>Imagem:</strong> ${letter.emoji}</div><div class="study-line"><strong>Som:</strong> ${letter.sound}</div><div class="study-line"><strong>Exemplo:</strong> ${letter.example}</div><div class="study-line"><strong>Tradução:</strong> ${letter.translation}</div><div class="study-line"><strong>Explicação:</strong> ${letter.tip}</div><div class="row"><button id="letterSound">Ouvir letra</button><button id="letterExample">Ouvir exemplo</button></div><div class="exercise"><strong>Exercício:</strong> digite a letra minúscula correspondente.<input id="letterAnswer" placeholder="Digite aqui"><button id="letterCheck">Verificar</button><div id="letterFeedback" class="feedback"></div></div></div>`; qs('#letterSound').onclick = () => speak(letter.upper); qs('#letterExample').onclick = () => speak(letter.example); qs('#letterCheck').onclick = () => { const ok = qs('#letterAnswer').value.trim() === letter.lower; const feedback = qs('#letterFeedback'); feedback.className = 'feedback ' + (ok ? 'good' : 'bad'); feedback.textContent = ok ? 'Certo!' : 'Resposta correta: ' + letter.lower; if (ok) addXP(5); else loseHeart(); }; }
function setAudio(item) { currentAudio = item; qs('#audioCat').textContent = item.cat; qs('#audioRu').textContent = item.ru; qs('#audioPt').textContent = item.pt; qs('#audioPron').textContent = item.pron; qs('#audioAnswer').value = ''; qs('#audioFeedback').textContent = ''; }
function renderAudio() { setAudio(PHRASES[0]); const categories = [...new Set(PHRASES.map(item => item.cat))]; qs('#audioPlaylists').innerHTML = categories.map(cat => `<article class="playlist-card"><h3>${cat}</h3><p>${PHRASES.filter(item => item.cat === cat).length} frases úteis</p><button data-playlist="${cat}">Estudar</button></article>`).join(''); qsa('#audioPlaylists [data-playlist]').forEach(button => button.onclick = () => { const phrase = PHRASES.find(item => item.cat === button.dataset.playlist); if (phrase) setAudio(phrase); }); }
function renderWriting() { qs('#keyboard').innerHTML = [...ALPHABET.map(item => item.upper), ...ALPHABET.map(item => item.lower)].map(char => `<button data-key="${char}">${char}</button>`).join(''); qsa('#keyboard [data-key]').forEach(button => button.onclick = () => { qs('#writingInput').value += button.dataset.key; }); newWritingTask(); }
function newWritingTask() { qs('#writingModel').textContent = randomItem(PHRASES).ru; qs('#writingInput').value = ''; qs('#writingFeedback').textContent = ''; }
function compareText(input, expected) { if (input === expected) return 'Perfeito.'; return Array.from({ length: Math.max(input.length, expected.length) }).map((_, index) => input[index] === expected[index] ? (expected[index] || '') : `[${input[index] || '∅'}→${expected[index] || '∅'}]`).join(' '); }
function setSpeaking(item) { currentSpeaking = item; qs('#speakRu').textContent = item.ru; qs('#speakPt').textContent = item.pt; qs('#speakPron').textContent = item.pron; qs('#speakingFeedback').textContent = ''; }
function renderReview() { qs('#reviewSummary').innerHTML = `<div class="study-line"><strong>Unidades concluídas:</strong> ${state.completedLessons.length}</div><div class="study-line"><strong>Itens na revisão:</strong> ${state.reviewQueue.length}</div><div class="study-line"><strong>Objetivo:</strong> ${state.profile.goal}</div><div class="study-line"><strong>Dica:</strong> ouça, traduza, pronuncie e escreva antes da prova.</div>`; currentReview = state.reviewQueue[0] || randomItem(PHRASES); showReview(); }
function showReview() { const item = currentReview || randomItem(PHRASES); qs('#reviewCard').innerHTML = `<div class="review-russian">${item.ru}</div><div><strong>Tradução:</strong> ${item.pt}</div><div><strong>Pronúncia:</strong> ${item.pron || translit(item.ru)}</div><div><strong>Explicação:</strong> revise com áudio e escrita.</div>`; qs('#reviewAnswer').value = ''; qs('#reviewFeedback').textContent = ''; }
function renderExam(level) { const pool = COURSE_UNITS.filter(unit => unit.level === level).flatMap(unit => unit.items).map(itemFrom); currentExam = (pool.length ? pool : PHRASES).slice(0, 10); qs('#examArea').innerHTML = `<div class="panel"><h2>Prova ${level}</h2>${currentExam.map((item, index) => `<div class="exam-question"><h3>${index + 1}. ${index % 3 === 0 ? 'Traduza' : index % 3 === 1 ? 'Pronúncia' : 'Copie em russo'}</h3><p><strong>Russo:</strong> ${item.ru}</p><p><strong>Tradução:</strong> ${item.pt}</p><p><strong>Pronúncia:</strong> ${item.pron || translit(item.ru)}</p><button data-exam-sound="${item.ru}">Ouvir</button><input data-exam-index="${index}" data-answer="${index % 3 === 0 ? item.pt : index % 3 === 1 ? (item.pron || translit(item.ru)) : item.ru}" placeholder="Resposta"><div class="feedback"></div></div>`).join('')}<button id="finishExam">Finalizar prova</button><div id="examResult" class="feedback"></div></div>`; qsa('[data-exam-sound]').forEach(button => button.onclick = () => speak(button.dataset.examSound)); qs('#finishExam').onclick = () => { let score = 0; qsa('[data-exam-index]').forEach(input => { const ok = norm(input.value) === norm(input.dataset.answer); const feedback = input.nextElementSibling; feedback.className = 'feedback ' + (ok ? 'good' : 'bad'); feedback.textContent = ok ? 'Certo' : 'Resposta: ' + input.dataset.answer; if (ok) score += 1; else { const item = currentExam[Number(input.dataset.examIndex)]; if (item) state.reviewQueue.push(item); } }); qs('#examResult').textContent = `Resultado: ${score}/${currentExam.length}`; if (score >= 7) addXP(100); else loseHeart(); saveState(); }; }
function renderGame(type = 'builder') { const item = randomItem(PHRASES); if (type === 'builder') { const words = item.ru.replace(/[.!?—]/g, '').split(' ').sort(() => Math.random() - 0.5); qs('#gameArea').innerHTML = `<div class="panel game-box"><h2>Montar frase</h2><p>${item.pt}</p><div id="target" class="game-target"></div><div class="words">${words.map(word => `<button data-word="${word}">${word}</button>`).join('')}</div><button id="checkBuilder">Verificar</button><button id="hearBuilder">Ouvir</button><div id="gameFeedback" class="feedback"></div></div>`; qsa('[data-word]').forEach(button => button.onclick = () => { const target = qs('#target'); target.textContent = clean(target.textContent + ' ' + button.dataset.word); button.disabled = true; }); qs('#checkBuilder').onclick = () => { const ok = norm(qs('#target').textContent) === norm(item.ru.replace(/[.!?—]/g, '')); const feedback = qs('#gameFeedback'); feedback.className = 'feedback ' + (ok ? 'good' : 'bad'); feedback.textContent = ok ? 'Certo!' : 'Frase: ' + item.ru; if (ok) addXP(20); else loseHeart(); }; qs('#hearBuilder').onclick = () => speak(item.ru); } else if (type === 'sound') { const options = [item.pt, ...PHRASES.filter(entry => entry.pt !== item.pt).slice(0, 3).map(entry => entry.pt)].sort(() => Math.random() - 0.5); qs('#gameArea').innerHTML = `<div class="panel game-box"><h2>Caça-som</h2><button id="playGameSound">Ouvir</button><div class="words">${options.map(option => `<button data-opt="${option}">${option}</button>`).join('')}</div><div id="gameFeedback" class="feedback"></div></div>`; qs('#playGameSound').onclick = () => speak(item.ru); qsa('[data-opt]').forEach(button => button.onclick = () => { const ok = button.dataset.opt === item.pt; const feedback = qs('#gameFeedback'); feedback.className = 'feedback ' + (ok ? 'good' : 'bad'); feedback.textContent = ok ? 'Certo!' : 'Resposta: ' + item.pt; if (ok) addXP(20); else loseHeart(); }); } else if (type === 'typing') { qs('#gameArea').innerHTML = `<div class="panel game-box"><h2>Digitação</h2><div class="game-target">${item.ru}</div><input id="typingInput"><button id="checkTyping">Verificar</button><button id="hearTyping">Ouvir</button><div id="gameFeedback" class="feedback"></div></div>`; qs('#hearTyping').onclick = () => speak(item.ru); qs('#checkTyping').onclick = () => { const ok = qs('#typingInput').value.trim() === item.ru; const feedback = qs('#gameFeedback'); feedback.className = 'feedback ' + (ok ? 'good' : 'bad'); feedback.textContent = ok ? 'Perfeito!' : compareText(qs('#typingInput').value.trim(), item.ru); if (ok) addXP(25); else loseHeart(); }; } else { qs('#gameArea').innerHTML = `<div class="panel game-box"><h2>Cartas rápidas</h2>${studyHTML(item)}<button id="nextCard">Próxima</button></div>`; wireStudy(qs('#gameArea')); qs('#nextCard').onclick = () => renderGame('cards'); } }
function renderDictionary(query = '') { const q = norm(query); const items = allItems().filter(item => !q || norm(item.ru).includes(q) || norm(item.pt).includes(q) || norm(item.pron).includes(q)).slice(0, 48); qs('#dictResults').innerHTML = items.map(item => `<article class="dict-card"><h3>${item.ru}</h3><div><strong>Tradução:</strong> ${item.pt}</div><div><strong>Pronúncia:</strong> ${item.pron || translit(item.ru)}</div><div><strong>Categoria:</strong> ${item.cat}</div><button data-dict-sound="${item.ru}">Ouvir</button><button data-dict-study="${item.ru}" class="ghost">Estudar</button></article>`).join('') || `<div class="panel">Nada encontrado.</div>`; qsa('[data-dict-sound]').forEach(button => button.onclick = () => speak(button.dataset.dictSound)); qsa('[data-dict-study]').forEach(button => button.onclick = () => { showSection('teacher'); addAI(buildTeacherReply(button.dataset.dictStudy)); }); }
function renderCulture() { qs('#cultureGrid').innerHTML = CULTURE_TOPICS.map((topic, index) => `<article class="culture-card" data-culture="${index}"><div class="icon">${topic.icon}</div><h3>${topic.title}</h3><p>${topic.short}</p><button>Ver conteúdo</button></article>`).join(''); qsa('#cultureGrid [data-culture]').forEach(card => card.onclick = () => showCulture(Number(card.dataset.culture))); showCulture(0); }
function showCulture(index) { const topic = CULTURE_TOPICS[index]; qs('#cultureDetail').innerHTML = `<div class="panel"><p class="tag">Cultura</p><h2>${topic.icon} ${topic.title}</h2><p>${topic.text}</p><h3>Palavras úteis</h3><div class="quick">${topic.words.map(word => { const item = itemFrom(word); return `<button data-culture-word="${item.ru}"><strong>${item.ru}</strong><span>${item.pt} · ${item.pron || translit(item.ru)}</span></button>`; }).join('')}</div>${topic.recipe ? `<div class="recipe"><h3>Receita</h3><p>${topic.recipe}</p></div>` : ''}</div>`; qsa('[data-culture-word]').forEach(button => button.onclick = () => speak(button.dataset.cultureWord)); }
function renderProfile() { qs('#profileName').value = state.profile.name || ''; qs('#profileGoal').value = state.profile.goal || 'viagem'; qs('#profileLevel').value = state.profile.level || 'iniciante'; const percent = Math.min(100, Math.round((state.completedLessons.length / COURSE_UNITS.length) * 100)); qs('#profileProgress').innerHTML = `<p><strong>XP:</strong> ${state.xp}</p><p><strong>Nível:</strong> ${state.level}</p><p><strong>Unidades:</strong> ${state.completedLessons.length}/${COURSE_UNITS.length}</p><div class="progress"><span style="width:${percent}%"></span></div><p><strong>Objetivo:</strong> ${state.profile.goal}</p>`; }
function extractRussian(text) { const match = String(text).match(/[А-Яа-яЁё][А-Яа-яЁё\s,.!?—-]*/); return match ? clean(match[0]) : text; }
function buildTeacherReply(input) { const found = findItem(input); if (found) return `Russo: ${found.ru}\nTradução: ${found.pt}\nPronúncia: ${found.pron || translit(found.ru)}\nExplicação: use "${found.ru}" quando quiser dizer "${found.pt}". Ouça, repita, escreva e responda.\nPerguntas:\n1. Qual é a tradução?\n2. Como se pronuncia?\n3. Copie em russo: ${found.ru}`; const q = norm(input); if (q.includes('prova') || q.includes('revis')) return `Russo: Мне нужно повторить.\nTradução: Eu preciso revisar.\nPronúncia: mne nuzhno povtorit\nExplicação: revise saudações, apresentação, viagem, áudio, escrita e cultura antes da prova.\nPerguntas:\n1. O que significa повторить?\n2. Qual é a tradução?\n3. Copie em russo.`; if (q.includes('viagem')) return `Russo: Где метро?\nTradução: Onde fica o metrô?\nPronúncia: gde metro\nExplicação: use Где para perguntar onde fica um lugar. Troque метро por гостиница, музей ou парк.\nPerguntas:\n1. O que significa Где?\n2. Como pedir hotel?\n3. Copie: Где метро?`; if (q.includes('gramática') || q.includes('gramatica')) return `Russo: Я учу русский язык.\nTradução: Eu estudo a língua russa.\nPronúncia: ya uchu russkiy yazyk\nExplicação: Я significa eu. Русский язык significa língua russa. No russo, os finais mudam conforme o papel da palavra na frase, mas você pode começar decorando estruturas prontas.\nPerguntas:\n1. O que significa Я?\n2. O que significa русский язык?\n3. Copie a frase.`; return `Russo: Я учу русский язык.\nTradução: Eu estudo a língua russa.\nPronúncia: ya uchu russkiy yazyk\nExplicação: frase base para começar. Я significa eu. Русский язык significa língua russa.\nPerguntas:\n1. O que significa Я?\n2. O que significa русский язык?\n3. Copie a frase.`; }
function addMessage(type, text) { const div = document.createElement('div'); div.className = 'message ' + type; div.textContent = text; if (type === 'ai') { const actions = document.createElement('div'); actions.className = 'message-actions'; const hear = document.createElement('button'); hear.textContent = 'Ouvir'; hear.onclick = () => speak(extractRussian(text)); const review = document.createElement('button'); review.textContent = 'Salvar revisão'; review.onclick = () => { const item = itemFrom(extractRussian(text)); if (!state.reviewQueue.find(entry => norm(entry.ru) === norm(item.ru))) state.reviewQueue.push(item); saveState(); toast('Salvo'); }; actions.append(hear, review); div.append(actions); } const chatBox = qs('#chatBox'); chatBox.append(div); chatBox.scrollTop = chatBox.scrollHeight; }
function addAI(text) { addMessage('ai', text); }
function sendChatMessage() { const input = qs('#chatInput'); const value = clean(input.value); if (!value) return; addMessage('user', value); input.value = ''; setTimeout(() => addAI(buildTeacherReply(value)), 180); }
function renderAll() { renderStats(); renderCourse(); renderAlphabet(); renderAudio(); renderWriting(); setSpeaking(PHRASES[0]); renderReview(); renderGame('builder'); renderDictionary(''); renderCulture(); renderProfile(); const chatBox = qs('#chatBox'); if (chatBox && !chatBox.dataset.started) { chatBox.dataset.started = '1'; addAI('Russo: Привет\nTradução: Olá\nPronúncia: privet\nExplicação: bem-vindo ao PUTIRUSU. Escolha uma aula ou me peça uma explicação.\nPerguntas:\n1. O que significa Привет?\n2. Como se pronuncia?\n3. Copie em russo: Привет'); } }
function wireEvents() { qs('#menuBtn').onclick = () => qs('#sidebar').classList.toggle('open'); qsa('nav button[data-screen]').forEach(button => button.onclick = () => showSection(button.dataset.screen)); qsa('[data-go]').forEach(button => button.onclick = () => showSection(button.dataset.go)); qs('#startBtn').onclick = showOnboarding; qs('#skipBtn').onclick = () => { state.onboarded = true; saveState(); enterApp(); }; qs('#saveOnboarding').onclick = () => { state.profile = { name: qs('#userName').value, goal: qs('#userGoal').value, level: qs('#userLevel').value }; state.onboarded = true; saveState(); enterApp(); }; qs('#continueCourse').onclick = () => openLesson(state.completedLessons.length < COURSE_UNITS.length ? state.completedLessons.length : 0); qs('#letterQuiz').onclick = () => showLetter(Math.floor(Math.random() * ALPHABET.length)); qs('#randomAudio').onclick = () => setAudio(randomItem(PHRASES)); qs('#playAudio').onclick = () => speak(currentAudio.ru); qs('#repeatAudio').onclick = () => { speak(currentAudio.ru); setTimeout(() => speak(currentAudio.ru), 1400); setTimeout(() => speak(currentAudio.ru), 2800); }; qs('#slowAudio').onclick = () => speak(currentAudio.ru, 0.65); qs('#checkAudio').onclick = () => { const ok = norm(qs('#audioAnswer').value) === norm(currentAudio.pt); const feedback = qs('#audioFeedback'); feedback.className = 'feedback ' + (ok ? 'good' : 'bad'); feedback.textContent = ok ? 'Certo!' : 'Resposta: ' + currentAudio.pt; if (ok) addXP(12); else { state.reviewQueue.push(currentAudio); saveState(); } }; qs('#newWriting').onclick = newWritingTask; qs('#hearWriting').onclick = () => speak(qs('#writingModel').textContent); qs('#clearWriting').onclick = () => { qs('#writingInput').value = ''; }; qs('#checkWriting').onclick = () => { const input = qs('#writingInput').value.trim(); const expected = qs('#writingModel').textContent; const ok = input === expected; const feedback = qs('#writingFeedback'); feedback.className = 'feedback ' + (ok ? 'good' : 'bad'); feedback.textContent = ok ? 'Correto!' : compareText(input, expected); if (ok) addXP(15); else loseHeart(); }; qs('#checkText').onclick = () => { const value = qs('#textInput').value.trim(); const ok = /[А-Яа-яЁё]/.test(value) && value.split(/[.!?]/).filter(item => item.trim()).length >= 2; const feedback = qs('#textFeedback'); feedback.className = 'feedback ' + (ok ? 'good' : 'bad'); feedback.textContent = ok ? 'Bom texto!' : 'Escreva pelo menos duas frases em russo.'; if (ok) addXP(25); }; qs('#newSpeaking').onclick = () => setSpeaking(randomItem(PHRASES)); qs('#hearSpeaking').onclick = () => speak(currentSpeaking.ru); qs('#recordSpeaking').onclick = () => listen(result => { const ok = norm(result) === norm(currentSpeaking.ru); const feedback = qs('#speakingFeedback'); feedback.className = 'feedback ' + (ok ? 'good' : 'bad'); feedback.textContent = `Você falou: ${result}\n${ok ? 'Muito bom!' : 'Esperado: ' + currentSpeaking.ru}`; if (ok) addXP(20); else { state.reviewQueue.push(currentSpeaking); saveState(); } }); qs('#buildReview').onclick = renderReview; qs('#hearReview').onclick = () => speak((currentReview || randomItem(PHRASES)).ru); qs('#nextReview').onclick = () => { currentReview = state.reviewQueue.length ? randomItem(state.reviewQueue) : randomItem(PHRASES); showReview(); }; qs('#checkReview').onclick = () => { const item = currentReview || randomItem(PHRASES); const answer = qs('#reviewAnswer').value; const ok = norm(answer) === norm(item.pt) || norm(answer) === norm(item.ru); const feedback = qs('#reviewFeedback'); feedback.className = 'feedback ' + (ok ? 'good' : 'bad'); feedback.textContent = ok ? 'Certo!' : `Resposta: ${item.pt} ou ${item.ru}`; if (ok) addXP(10); else loseHeart(); }; qsa('[data-exam]').forEach(button => button.onclick = () => renderExam(button.dataset.exam)); qsa('[data-game]').forEach(button => button.onclick = () => renderGame(button.dataset.game)); qs('#dictSearch').onclick = () => renderDictionary(qs('#dictInput').value); qs('#dictInput').addEventListener('input', e => renderDictionary(e.target.value)); qs('#sendChat').onclick = sendChatMessage; qs('#chatInput').addEventListener('keydown', e => { if (e.key === 'Enter') sendChatMessage(); }); qs('#micChat').onclick = () => listen(text => { qs('#chatInput').value = text; sendChatMessage(); }); qsa('[data-prompt]').forEach(button => button.onclick = () => { qs('#chatInput').value = button.dataset.prompt; sendChatMessage(); }); qs('#saveProfile').onclick = () => { state.profile = { name: qs('#profileName').value, goal: qs('#profileGoal').value, level: qs('#profileLevel').value }; state.onboarded = true; saveState(); renderProfile(); toast('Perfil salvo'); }; qs('#resetProgress').onclick = () => { if (confirm('Zerar progresso?')) { localStorage.removeItem(STORAGE_KEY); window.location.reload(); } }; }
function init() { setImageFallbacks(); wireEvents(); renderStats(); setTimeout(() => { hideSplash(); if (state.onboarded) { enterApp(); } else { showWelcome(); } }, 1400); setTimeout(() => { if (qs('#splash')) hideSplash(); if (qs('#app').classList.contains('app-hidden') && !qs('#welcome').classList.contains('show') && !qs('#onboarding').classList.contains('show')) { if (state.onboarded) enterApp(); else showWelcome(); } }, 2600); }
document.addEventListener('DOMContentLoaded', init);
